var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"나가파샤는 어디에 있죠?","JPN":"そのナーガパーシャっていうのはどこにあるんですか？","ENG":"So, where is Nagapasha?","TWN":"那種東西會放在哪裡？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"나가파샤는 평소엔 함교 중앙에 간단한 봉인 조치를 한 뒤 보관하고 있었습니다.","JPN":"ナーガパーシャは、普段は艦橋の中央に簡単な封印措置をしてから保管していました。","ENG":"Nagapasha was usually stored in the bridge's center after some simple sealing processes.","TWN":"那伽羂索平時被簡單封印後保存在艦橋中心。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"봉인은 전대원의 생체 인식 코드로 해제할 수 있죠.","JPN":"封印は戦隊員の生体認識コードで解除できます。","ENG":"The seal can be removed with any division members' biometric code.","TWN":"封印可以透過隊員的生物識別碼來解除。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아마 바루나스트라도 우리의 속셈을 알고 있을 겁니다. 서둘러야 해요.","JPN":"おそらくヴァルナストラも私たちの計画を知っているはずです。急がなければいけません。","ENG":"I'm sure Varunastra already knows what we're up to, so we must hurry.","TWN":"我怕伐樓拿之艦已經知道我們的打算，我們得趕快行動。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"다행히 우리가 먼저 도착했군요.","JPN":"幸い、後れをとってはいませんね。","ENG":"Thankfully, it seems that we arrived first.","TWN":"幸好我們先到了。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이곳이 바루나스트라의…… 함교.","JPN":"ここがヴァルナストラの……艦橋。","ENG":"This is Varunastra's... bridge.","TWN":"這裡是伐樓拿之艦的……艦橋。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그럼 봉인을 해제하겠습니다.","JPN":"それでは、封印を解除します。","ENG":"Then, I'll remove the seal.","TWN":"來解除封印吧。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>생체 인식 코드 활성화. </color>","JPN":"<color=#ffd34c>生体認識コード活性化。</color>","ENG":"<color=#ffd34c>Biometric authentication code activated.</color>","TWN":"<color=#ffd34c>生物識別代碼啟動。</color>"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아티팩트, 나가파샤 봉인 해제. </color>","JPN":"<color=#ffd34c>アーティファクト、ナーガパーシャの封印解除。</color>","ENG":"<color=#ffd34c>Seal of Artifact Nagapasha removed.</color>","TWN":"<color=#ffd34c>人造神器，那伽羂索封印解除。</color>"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 일이 너무 쉽게 흘러가면 도리어 불안해지는 느낌은 뭘까요?","JPN":"あはは。こんなに簡単過ぎるとどうしてかえって不安になるんでしょうかね？","ENG":"Ah hah hah. Why do I feel anxious about all of this going so smoothly?","TWN":"呵呵呵，事情順利得反而讓人感到不安呢？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"왠지 그 고래라면 다 아는 듯이 나타날 것 같은데…….","JPN":"なんとなくあのクジラならすべてを見通していたかのように現われそうな気が……","ENG":"That whale should appear by now, acting like it knew everything...","TWN":"總覺得那隻鯨魚會冷不防地出現……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이곳에 올 줄 알고 있었습니다. ","JPN":"ここに来ると思っていました。 ","ENG":"I knew you would come here.","TWN":"我就知道你們會來這裡。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이럴 줄 알았어…… 역시 뭔가 있었다니까.","JPN":"ほら……やっぱりこうなると思った。","ENG":"Told you something was up...","TWN":"果，果然……有問題。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"나가파샤가 없으면 <color=#ffd34c>차원 닻</color>은 무용지물이니까요.","JPN":"ナーガパーシャがないと<color=#ffd34c>次元錨</color>は何の意味も成しませんからね。","ENG":"Without Nagapasha, the <color=#ffd34c>Dimension Anchor</color> is useless.","TWN":"沒有那伽羂索，<color=#ffd34c>次元錨</color>就是一個廢鐵。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이미 육신의 한계에서 벗어난 우리로는 봉인을 해제할 수 없었습니다.","JPN":"すでに肉体の限界から解放された私たちは、封印を解除することができませんでした。","ENG":"Being freed from the limits of the body, we could not remove the seal.","TWN":"已經脫離肉體限制的我們無法解除那個封印。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신과 불순물이라면, 이 봉인을 해제하기 위해 올 것이라 예상했죠.","JPN":"あなたと不純物なら、この封印を解除するために来ると予想していたのです。","ENG":"But I expected that you and the impurity would come here to remove it.","TWN":"但我知道你和這個雜質會來解除封印。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바루나스트라의 내부가 다시 변형되기 시작했어요!","JPN":"ヴァルナストラの内部がまた変形してます！","ENG":"Varunastra has started to transform again!","TWN":"伐樓拿之艦的內部又開始變形了！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이곳은 일종의 이면 세계. 공간을 뒤틀어버리는 건 일도 아닙니다.","JPN":"ここはある種の裏世界。空間を歪ませるのは簡単です。","ENG":"This place is a part of the Counterside. Warping space can be easily done.","TWN":"這裡也算是異界，扭曲空間不費吹灰之力。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"설마 우리가 이런 사소한 부분도 신경 쓰지 못할 거라 생각했나요?","JPN":"まさか、こんな細部にまでは私たちの目が届いていないとでも期待していたのですか？","ENG":"Did you really think that we would look over these trivial details?","TWN":"你以為我們連這種小事都不會注意到嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 전대의 전술, 그리고 함선의 기술을 모두 응용할 수 있습니다.","JPN":"私たちは戦隊の戦術、そして艦船の技術をすべて応用できます。","ENG":"We are able to apply all of our division's tactics and the ship's technology.","TWN":"我們不只可以使用戰隊的戰術，還有艦船的技術。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이런 식으로 좌표를 비트는 것조차, 당신이 봉인을 해제했으니 가능한 일이지요.","JPN":"このように座標を歪ませることも、あなたが封印を解除したからできることなのです。","ENG":"Even distorting the coordinates like this is only possible because you removed the seal.","TWN":"用這種方式扭曲座標，也是因為你解除封印才辦得到的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};